// Domain Availability Check — Real Porkbun API with graceful degradation
// Reads Porkbun credentials from webhook body context (injected by bridge server T01).
// If credentials are missing, falls back to simulated data.
// Rate limit: Porkbun allows 1 check per 10 seconds — we wait 11s between calls.

const body = $input.first().json.body;
const { projectId, stageKey, executionId, subStage } = body;
const selectedName = body.context?.selectedName || 'Nexus';
const porkbunApiKey = body.context?.porkbunApiKey;
const porkbunApiSecret = body.context?.porkbunApiSecret;

const baseName = selectedName.toLowerCase().replace(/[^a-z0-9]/g, '');
const tlds = ['com', 'io', 'dev', 'co', 'app', 'ai'];

// --- Helper: sleep for rate limiting ---
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// --- Simulated fallback data (used when credentials are missing) ---
function getSimulatedSignals(baseName) {
  return [
    { domain: `${baseName}.com`, status: 'taken', registrar: 'Simulated', price: null },
    { domain: `${baseName}.io`, status: 'premium', registrar: 'Simulated', price: '$2,495/yr' },
    { domain: `${baseName}.dev`, status: 'available', registrar: 'Simulated', price: '$12/yr' },
    { domain: `${baseName}.co`, status: 'taken', registrar: 'Simulated', price: null },
    { domain: `${baseName}.app`, status: 'available', registrar: 'Simulated', price: '$14/yr' },
    { domain: `${baseName}.ai`, status: 'premium', registrar: 'Simulated', price: '$4,999/yr' }
  ];
}

// --- Graceful degradation: no credentials ---
if (!porkbunApiKey || !porkbunApiSecret) {
  return {
    json: {
      projectId,
      stageKey,
      executionId,
      subStage: subStage || 'domain_signals',
      domainResult: {
        selectedName,
        signals: getSimulatedSignals(baseName),
        checkedAt: new Date().toISOString(),
        source: 'simulated',
        dataOrigin: 'Simulated data — Porkbun API credentials not configured',
        disclaimer: 'Domain availability is a point-in-time check. Results may change.',
        metadata: {
          engine: 'n8n-plan-domain-v1-simulated',
          source: 'simulated',
          dataOrigin: 'Simulated data — Porkbun API credentials not configured'
        }
      }
    }
  };
}

// --- Real Porkbun API calls ---
const signals = [];
const errors = [];

for (let i = 0; i < tlds.length; i++) {
  const tld = tlds[i];
  const domain = `${baseName}.${tld}`;

  // Rate limiting: wait 11 seconds between calls (skip delay for first call)
  if (i > 0) {
    await sleep(11000);
  }

  try {
    const response = await fetch(
      `https://api.porkbun.com/api/json/v3/domain/checkDomain/${domain}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          apikey: porkbunApiKey,
          secretapikey: porkbunApiSecret
        })
      }
    );

    const data = await response.json();

    if (data.status === 'ERROR') {
      errors.push({ domain, error: data.message || 'Unknown API error', code: response.status });
      continue;
    }

    // Translate Porkbun response to renderer-compatible shape
    let status;
    if (data.avail === 'yes') {
      status = data.premium === 'yes' ? 'premium' : 'available';
    } else {
      status = 'taken';
    }

    const priceNum = parseFloat(data.price);
    const formattedPrice = !isNaN(priceNum) ? `$${priceNum.toFixed(2)}/yr` : null;
    const renewalNum = parseFloat(data.renewalPrice);
    const formattedRenewal = !isNaN(renewalNum) ? `$${renewalNum.toFixed(2)}/yr` : null;
    const regularNum = parseFloat(data.regularPrice);
    const formattedRegular = !isNaN(regularNum) ? `$${regularNum.toFixed(2)}/yr` : null;

    signals.push({
      domain,
      status,
      price: formattedPrice,
      registrar: 'Porkbun',
      renewalPrice: formattedRenewal,
      regularPrice: formattedRegular,
      premium: data.premium === 'yes',
      firstYearPromo: data.price && data.regularPrice && parseFloat(data.price) < parseFloat(data.regularPrice)
    });
  } catch (err) {
    errors.push({ domain, error: err.message || 'Network error', code: 'NETWORK_ERROR' });
  }
}

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'domain_signals',
    domainResult: {
      selectedName,
      signals,
      checkedAt: new Date().toISOString(),
      source: 'porkbun-api',
      dataOrigin: 'Porkbun Domain Availability API',
      disclaimer: 'Domain availability is a point-in-time check. Results may change. Pricing is sourced from Porkbun and subject to change.',
      metadata: {
        engine: 'porkbun-live-v1',
        source: 'porkbun-api',
        dataOrigin: 'Porkbun Domain Availability API',
        errors: errors.length > 0 ? errors : undefined
      }
    }
  }
};
